发布 — 订阅模式又叫观察者模式，它定义对象间的一种一对多的依赖关系，当一个对象的状态发生改变时，所有依赖于它的对象都将得到通知。

发布订阅模式的基础实现

```JS
  // 利用发布订阅模式实现自定义事件(买菜，买车，买房子...)
  // 例如：买菜 - 买青菜，买白菜，买番茄.....
  // this.message['买菜'] = [function(){买青菜},function(){买白菜}...]
  // this.message['买车'] = [function(){买宝马},function(){买奔驰}...]
  // this.message['买房'] = [function(){买别墅},function(){买大平层}...]
  // 买菜：事件类型   +  事件处理函数

  //利用Observer进行自定义事件的开发。
  //添加事件 - on
  //执行事件 - emit
  //删除事件 - remove
  class ob {
    constructor() {
      this.message = {};
    }
    //订阅事件
    on(type, fn) {
      // 如果不存在事件先初始化一个数组
      if (!this.message[type]) {
        this.message[type] = [];
      }
      // 将传入的回调函数推入该事件的数组中
      this.message[type].push(fn);
    }
    //发布事件 (emit)
    emit(type, ...args) {
      // 防止报错，如果没订阅过这个事件就直接发布的话直接return
      if (!this.message[type]) return;
      //args是参数，emit执行该类型里的所有函数，代表发布事件之后所有订阅了该事件的对象接收到了通知
      this.message[type].forEach((item) => {
        item(...args);
      });
    }
    //取消订阅
    remove(type, fn) {
      // 防止报错，防止取消订阅不存在的类型导致报错
      if (!this.message[type]) return;
      // 如果没传入函数就删除该类型和该类型里的所有函数
      if (!fn) {
        delete this.message[type];
      } else {
        this.message[type] = this.message[type].filter((item) => item !== fn);
      }
    }
  }
  const event = new ob();
  function fn1(food) {
    console.log(`买菜1收到通知，需要买：${food}`);
  }
  function fn2(food, weight) {
    console.log(`买菜2收到通知，需要买：${weight}的${food}`);
  }

  // 订阅事件
  event.on("买菜", fn1);
  event.on("买菜", fn2);
  console.log("event.message", event.message);
  // 发布事件，并传递数据
  console.log("--- 第一次发布 ---");
  event.emit("买菜", "西红柿", "两斤");
  // 预期输出:
  // 买菜1收到通知，需要买：西红柿
  // 买菜2收到通知，需要买：两斤的西红柿

  // 移除 fn1 的订阅
  event.remove("买菜", fn1);
  console.log("event.message", event.message);
  console.log("--- 第二次发布 ---");
  event.emit("买菜", "土豆", "三斤");
  // 预期输出（fn1已被移除，只有fn2会执行）:
  // 买菜2收到通知，需要买：三斤的土豆
```

