1. 题解 1：暴力解法 双重 for 循环双指针移动，存储结果找到最长字串（O(n²)复杂度）

```JavaScript

var lengthOfLongestSubstring = function (s) {
    if(s.length === 1)return 1;
    let str = "";
    const len = s.length;
    for (let i = 0; i < s.length; i++) {
      let currentStr = s[i];
      for (let j = i + 1; j < len; j++) {
        if (currentStr.indexOf(s[j]) !== -1) {
          break;
        } else {
          currentStr += s[j];
        }
      }
      if (currentStr.length > str.length) str = currentStr;
    }
    return str.length;
};
```

2. 题解 2：使用滑块思想，移动滑块存储当前最长字符串（O(n²)复杂度）

```JavaScript

var lengthOfLongestSubstring = function (s) {
  let str = "";
    let len = s.length;
    if (len === 1) return 1;
    for (let i = 0; i < len; i++) {
      let currentStr = s[i];
      let j = i + 1;
      while (currentStr.indexOf(s[j]) == -1) {
        currentStr += s[j];
        j++;
        // 处理越界
        if (j >= len) {
          j = len - 1;
        }
      }

      if (currentStr.length > str.length) str = currentStr;
      // 如果j走到头了就不用判断了
      if (j === len - 1) {
        break;
      }
      i = s.indexOf(s[j], i);
    }
    return str.length;
};
```

3. 题解 3：使用滑块思想+Set 结构去除重复值（O(n)复杂度）

```JavaScript
var lengthOfLongestSubstring = function (s) {
    let seen = new Set(); // 存储当前窗口的字符
    let left = 0,
      maxLen = 0;
    for (let right = 0; right < s.length; right++) {
      while (seen.has(s[right])) {
        seen.delete(s[left]);
        left++;
      }
      seen.add(s[right]);
      maxLen = maxLen > seen.size ? maxLen : seen.size;
    }
    return maxLen;
};
```



