  'component' true,          总是包含 'component'
  'is-active' isActive,      'is-active' 会被包含
  'has-error' hasError,      'has-error' 会被忽略
  'theme-dark' theme === 'dark'  'theme-dark' 会被包含
};
 = "component is-active theme-dark"


